patch:
diff --git a/drivers/acpi/dock.c b/drivers/acpi/dock.c
index 5b30b8d..de397fd 100644
--- a/drivers/acpi/dock.c
+++ b/drivers/acpi/dock.c
@@ -381,6 +381,7 @@ static void hotplug_dock_devices(struct dock_station *ds, u32 event)

 	mutex_lock(&ds->hp_lock);

+	printk(KERN_INFO "DOCK: hotplug_dock_devices()\n");
 	/*
 	 * First call driver specific hotplug functions
 	 */
@@ -671,6 +672,8 @@ static int handle_eject_request(struct dock_station *ds, u32 event)
 	if (dock_in_progress(ds))
 		return -EBUSY;

+	printk(KERN_INFO "DOCK: handle_eject_request\n");
+
 	/*
 	 * here we need to generate the undock
 	 * event prior to actually doing the undock
@@ -727,9 +730,12 @@ static void dock_notify(acpi_handle handle, u32 event, void *data)
 	 */
 	switch (event) {
 	case ACPI_NOTIFY_BUS_CHECK:
+		printk(KERN_INFO "BUS_CHECK\n");
 	case ACPI_NOTIFY_DEVICE_CHECK:
+		printk(KERN_INFO "DEVICE_CHECK\n");
 		if (!dock_in_progress(ds) && acpi_bus_get_device(ds->handle,
 		   &tmp)) {
+			printk(KERN_INFO "DOCK: Started docking\n");
 			begin_dock(ds);
 			dock(ds);
 			if (!dock_present(ds)) {
@@ -743,15 +749,18 @@ static void dock_notify(acpi_handle handle, u32 event, void *data)
 			complete_dock(ds);
 			dock_event(ds, event, DOCK_EVENT);
 			dock_lock(ds, 1);
+			printk(KERN_INFO "DOCK: Completed docking\n");
 			break;
 		}
 		if (dock_present(ds) || dock_in_progress(ds))
 			break;
 		/* This is a surprise removal */
+		printk(KERN_INFO "DOCK: Surprise removal\n");
 		surprise_removal = 1;
 		event = ACPI_NOTIFY_EJECT_REQUEST;
 		/* Fall back */
 	case ACPI_NOTIFY_EJECT_REQUEST:
+		printk(KERN_INFO "DOCK: EJECT_REQUEST\n");
 		begin_undock(ds);
 		if ((immediate_undock && !(ds->flags & DOCK_IS_ATA))
 		   || surprise_removal)
@@ -855,11 +864,15 @@ fdd_out:
 static ssize_t show_docked(struct device *dev,
 			   struct device_attribute *attr, char *buf)
 {
+	struct acpi_device *tmp;
+
 	struct dock_station *dock_station = *((struct dock_station **)
 		dev->platform_data);
-	return snprintf(buf, PAGE_SIZE, "%d\n", dock_present(dock_station));
+	return snprintf(buf, PAGE_SIZE, "%d\n",
+			acpi_bus_get_device(dock_station->handle, &tmp));

 }
+
 static DEVICE_ATTR(docked, S_IRUGO, show_docked, NULL);

 /*
diff --git a/drivers/acpi/dock.c b/drivers/acpi/dock.c
index 5b30b8d..afd5db3 100644
--- a/drivers/acpi/dock.c
+++ b/drivers/acpi/dock.c
@@ -855,10 +855,14 @@ fdd_out:
 static ssize_t show_docked(struct device *dev,
 			   struct device_attribute *attr, char *buf)
 {
+	struct acpi_device *tmp;
+
 	struct dock_station *dock_station = *((struct dock_station **)
 		dev->platform_data);
-	return snprintf(buf, PAGE_SIZE, "%d\n", dock_present(dock_station));

+	if (ACPI_SUCCESS(acpi_bus_get_device(dock_station->handle, &tmp)))
+		return snprintf(buf, PAGE_SIZE, "1\n");
+	return snprintf(buf, PAGE_SIZE, "0\n");
 }
 static DEVICE_ATTR(docked, S_IRUGO, show_docked, NULL);
